ep"}, {"question": "What ethical implications of ML could impact its adoption in healthcare?", "purpose": "Discuss the societal impact of technology.", "expected_depth": "deep"}, {"question": "How might the choice of algorithm affect the outcome of a supervised learning model?", "purpose": "Explore algorithmic impacts on results.", "expected_depth": "medium"}, {"question": "Can you think of a situation where unsupervised learning may be preferable? Why?", "purpose": "Encourage exploration of alternative learning methods.", "expected_depth": "medium"}, {"question": "In what ways can biases in data impact ML models?", "purpose": "Examine data ethics and quality.", "expected_depth": "deep"}, {"question": "What are some limitations of supervised learning that you can identify?", "purpose": "Identify challenges in the learning approach.", "expected_depth": "medium"}], "formative_assessments": [{"type": "Quick Poll", "description": "Poll students on their understanding of the differences between supervised and unsupervised learning.", "timing": "At the end of Section 3", "questions": ["Can you define supervised learning?", "Provide an example of unsupervised learning."]}, {"type": "Exit Ticket", "description": "Students submit a brief reflection on what they learned and one question they still have.", "timing": "At the end of the lecture", "questions": ["What is one key takeaway from today's lecture?", "What is one question you still have about ML?"]}], "suggested_activities": [{"activity_name": "Model Building Exercise", "activity_type": "Group", "description": "Groups will create a simple supervised learning model using provided datasets and discuss their approach.", "duration": "15 minutes", "learning_objective": "Apply ML concepts to a hands-on project.", "materials": ["Sample datasets", "Computers with ML software"], "instructions": "Guide groups to choose a dataset, define the problem, and outline their approach to building the model."}, {"activity_name": "Peer Teac